/**
 * 共享的尺寸约束行为接口
 * 定义了所有尺寸模式都支持的基础约束属性
 */
export interface SharedSizingBehavior {
    /** 最小宽度约束 */
    minWidth?: number | string;
    /** 最大宽度约束 */
    maxWidth?: number | string;
}
/**
 * 弹性尺寸行为接口
 * 基于 flex 布局的比例分配模式
 *
 *  @docgen
 */
export interface FlexSizingBehavior extends SharedSizingBehavior {
    /** 尺寸模式：弹性布局 */
    mode: 'flex';
    /** flex 比例值，决定元素在可用空间中的分配比例 */
    ratio?: number;
}
/**
 * 固定尺寸行为接口
 * 设置元素为固定宽度，不参与弹性布局
 *
 *  @docgen
 */
export interface FixedSizingBehavior extends SharedSizingBehavior {
    /** 尺寸模式：固定宽度 */
    mode: 'fixed';
    /** 固定的宽度值 */
    width: number | string;
}
/**
 * 内容包裹尺寸行为接口
 * 元素宽度根据内容自适应（类似 fit-content）
 *
 *  @docgen
 */
export interface HugSizingBehavior extends SharedSizingBehavior {
    /** 尺寸模式：内容包裹 */
    mode: 'hug';
}
/**
 * 尺寸行为联合类型
 * 支持四种不同的尺寸控制模式
 */
export type SizingBehavior = FlexSizingBehavior | FixedSizingBehavior | HugSizingBehavior;
/**
 * 将尺寸行为配置转换为 CSS 样式属性
 * @param sizing - 尺寸行为配置对象
 * @returns 对应的 CSS 样式属性
 */
export declare function resolveSizingBehavior(sizingBehavior: SizingBehavior): React.CSSProperties;
